import software.amazon.awssdk.auth.credentials.ProfileCredentialsProvider
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model._

object AWSService {
  private val region = Region.US_EAST_1
  private val credentialsProvider = ProfileCredentialsProvider.create()
  
  def listBucketContents(bucketName: String): List[String] = {
    val s3Client = S3Client.builder()
      .region(region)
      .credentialsProvider(credentialsProvider)
      .build()

    val listObjectsRequest = ListObjectsV2Request.builder()
      .bucket(bucketName)
      .build()

    val listObjectsResponse = s3Client.listObjectsV2(listObjectsRequest)

    if (listObjectsResponse.contents().isEmpty) {
      println("No objects found in the bucket.")
      List.empty
    } else {
      listObjectsResponse.contents().stream().map(_.key()).toList()
    }
  }

  def main(args: Array[String]): Unit = {
    val bucketName = "your-bucket-name"
    try {
      val contents = listBucketContents(bucketName)
      contents.foreach(println)
    } catch {
      case e: Exception =>
        println(s"An error occurred: ${e.getMessage}")
    }
  }
}